DROP TABLE IF EXISTS `hotel_room_stock`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `hotel_room_stock` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `room_type_id` int NOT NULL COMMENT '所属房型ID',
  `hotel_id` bigint NOT NULL COMMENT '冗余酒店ID，方便直接按酒店统计',
  `sale_date` date NOT NULL COMMENT '销售日期',
  `stock` int NOT NULL DEFAULT '0' COMMENT '当天剩余可预订库存',
  `price` decimal(10,2) NOT NULL COMMENT '当天实际售价(支持节假日动态调价)',
  `status` tinyint DEFAULT '1' COMMENT '销售状态: 0-停售, 1-在售',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_room_date` (`room_type_id`,`sale_date`),
  KEY `idx_hotel_date_stock` (`hotel_id`,`sale_date`,`stock`)
) ENGINE=InnoDB AUTO_INCREMENT=19252 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='每日房型库存与动态价格表';
