DROP TABLE IF EXISTS `image`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `image` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `target_id` bigint NOT NULL COMMENT '关联的目标ID(酒店ID/景点ID/房型ID/评论ID等)',
  `target_type` tinyint NOT NULL COMMENT '目标类型: 1-酒店, 2-房型, 3-景点, 4-评论 5-用户',
  `image_url` varchar(255) NOT NULL COMMENT '图片OSS地址或路径',
  `sort_order` int DEFAULT '0' COMMENT '排序权重(数字越小越靠前)',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_target` (`target_id`,`target_type`)
) ENGINE=InnoDB AUTO_INCREMENT=4931 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='通用多媒体资源关联表';
/*!40101 SET character_set_client = @saved_cs_client */;

