--
-- Table structure for table `spot`
--

DROP TABLE IF EXISTS `spot`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `spot` (
  `id` bigint NOT NULL COMMENT '主键ID',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景点名称',
  `city` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所在城市',
  `type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景点类型（如：自然景观、人文古迹、亲子游等）',
  `address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '详细地址',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '门票价格',
  `open_time` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '开放时间描述',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '景点详细介绍',
  `image_urls` text COLLATE utf8mb4_unicode_ci COMMENT '景点图片URL',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1-正常显示，0-隐藏/维护',
  `views` int DEFAULT '0' COMMENT '浏览次数',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `average_score` decimal(3,1) DEFAULT '0.0' COMMENT '景点平均评分',
  `comment_count` int DEFAULT '0' COMMENT '总评价人数',
  PRIMARY KEY (`id`),
  KEY `idx_city` (`city`),
  KEY `idx_type` (`type`),
  KEY `idx_name` (`name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='景点信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `spot`
--

LOCK TABLES `spot` WRITE;
